#include <cstdio>
#include <vector>
#include <algorithm>

using namespace std;

/**
 * Problem: Self-numbers 2
 * A self-number is a number that cannot be generated by any number n via d(n) = n + sum_of_digits(n).
 * Given N, we need to find the total number of self-numbers in [1, N] and output specific s_i-th self-numbers.
 * 
 * Constraints: N up to 10^7, K up to 5000, time limit 0.5s, memory limit 4096 KB.
 * Memory management: N=10^7 requires careful handling. std::vector<bool> uses 1 bit per element,
 * which for 10^7 is about 1.25 MB, fitting well within 4 MB.
 * Time complexity: O(N) to find all generators, O(N) to collect self-numbers. 
 * To meet the tight 0.5s limit, we use an optimized sum-of-digits approach.
 */

int sum_digits_small[100];

int main() {
    // Precompute the sum of digits for numbers 0-99 to speed up the main loop.
    for (int i = 0; i < 100; ++i) {
        int s = 0, t = i;
        while (t) {
            s += t % 10;
            t /= 10;
        }
        sum_digits_small[i] = s;
    }

    int N, K;
    // Use scanf for faster input reading.
    if (scanf("%d %d", &N, &K) != 2) return 0;

    // is_not_self[i] is true if i is a generator's result (d(n) = i for some n).
    // std::vector<bool> is a bit-packed specialization that uses roughly 1 bit per element.
    vector<bool> is_not_self(N + 1, false);

    for (int i = 1; i <= N; ++i) {
        int s = 0;
        int temp = i;
        // Fast calculation of sum of digits using precomputed values.
        // For N=10^7, there are at most 4 blocks of 2 digits.
        while (temp >= 100) {
            s += sum_digits_small[temp % 100];
            temp /= 100;
        }
        s += sum_digits_small[temp];
        
        int next_val = i + s;
        // If next_val is within range [1, N], mark it as not a self-number.
        if (next_val <= N) {
            is_not_self[next_val] = true;
        }
    }

    // We need to find the s_i-th self-number. Since s_i may not be sorted, 
    // we store them as pairs (index, original_position) and sort them.
    vector<pair<int, int>> sorted_s(K);
    for (int i = 0; i < K; ++i) {
        if (scanf("%d", &sorted_s[i].first) != 1) break;
        sorted_s[i].second = i;
    }
    sort(sorted_s.begin(), sorted_s.end());

    vector<int> results(K);
    int self_count = 0;
    int s_ptr = 0;
    // Single pass through the range [1, N] to count self-numbers and locate indices.
    for (int i = 1; i <= N; ++i) {
        if (!is_not_self[i]) {
            self_count++;
            // If the current self-number count matches one of the requested indices.
            if (s_ptr < K && self_count == sorted_s[s_ptr].first) {
                results[sorted_s[s_ptr].second] = i;
                s_ptr++;
            }
        }
    }

    // Final output.
    printf("%d\n", self_count);
    for (int i = 0; i < K; ++i) {
        printf("%d%c", results[i], (i == K - 1 ? '\n' : ' '));
    }

    return 0;
}

